const root = document.querySelector('[selector="list-record-4"]');
if (!root) return;

const table   = root.querySelector('table.record-list-table-secondary');
const wrapper = root.querySelector('.data-table');

if (!table || !wrapper) return;

const updateMaxRowsState = () => {
  const rows = table.querySelectorAll('tbody tr').length;
  if (rows >= 5) {
    wrapper.classList.add('max-rows');
  } else {
    wrapper.classList.remove('max-rows');
  }
};

updateMaxRowsState();

const cantidad_limite_frm_lista_coaseguro = Number(this.cantidad_limite_frm_lista_coaseguro);
const lista = Array.isArray(this.frm_lista_coaseguro)
      ? this.frm_lista_coaseguro
      : [];

    return lista.length >= cantidad_limite_frm_lista_coaseguro ? "true" : "false";

const lista = this.frm_lista_coaseguro || [];
let total = 0;

for (const row of lista) {
  if (!row) continue;
  total += row.frm_coaseguro_participacion || 0;
}

return total;

// 1. Si tenemos la lista en este contexto, la usamos para recalcular el total
  if (Array.isArray(this.frm_lista_coaseguro)) {
    const total = this.frm_lista_coaseguro.reduce((acc, row) => {
      const v = row && row.frm_coaseguro_participacion;
      const n = Number(v);
      return acc + (Number.isFinite(n) ? n : 0);
    }, 0);

    // Cacheamos en window para que el modal lo pueda reutilizar
    window.frm_lista_coaseguro_participacion_total = total;

    // Devuelve como número o string según lo que esperes
    return String(total); // o: return total;
  }

  // 2. Si no tenemos la lista (p. ej. dentro del modal), usamos el caché global
  if (typeof window.frm_lista_coaseguro_participacion_total !== 'undefined') {
    return String(window.frm_lista_coaseguro_participacion_total);
  }

  // 3. Si no hay nada cacheado todavía, devolvemos vacío o 0
  return '0'; // o '' si prefieres mostrar nada

const parseNum = (v) => {
  if (v == null) return null;
  if (typeof v === 'number') return v;

  const n = Number(
    v.toString()
      .trim()
      .replace(/\./g, '')  // quita separadores de miles tipo "1.234,56"
      .replace(',', '.')   // convierte coma decimal en punto
  );

  return Number.isFinite(n) ? n : null;
};

const rawVal       = this.frm_coaseguro_participacion;
const rawRestante  = this.frm_lista_coaseguro_participacion_maximo_dup;
const rawMaxEditar = this.frm_lista_coaseguro_participacion_maximo_editar;

let val       = parseNum(rawVal);
let restante  = parseNum(rawRestante);
let maxEditar = parseNum(rawMaxEditar);

let isEdit      = false;
let maxFromEdit = null;
let inputRef    = null;

// ------- Helper para ver si un contenedor [data-cy="..."] está visible -------
const isContainerVisible = (container) => {
  if (!container) return false;
  const dialog = container.querySelector('div[role="dialog"]');
  if (!dialog) return false;

  // Primero mira el style inline, si no, usa getComputedStyle
  const inlineDisplay = dialog.style && dialog.style.display;
  const display =
    inlineDisplay && inlineDisplay.trim() !== ''
      ? inlineDisplay
      : window.getComputedStyle(dialog).display;

  return display !== 'none';
};

// ---------------- Detectar si estamos en modo EDITAR ----------------
try {
  const editContainer = document.querySelector('[data-cy="modal-edit"]');

  if (editContainer && isContainerVisible(editContainer)) {
    isEdit = true;
    //console.log('Modo detectado: EDITAR');

    inputRef = editContainer.querySelector('input[name="frm_coaseguro_participacion"]');
    if (inputRef) {
      if (!inputRef.dataset.maxEditCaptured) {
        inputRef.dataset.maxEditCaptured = '1';

        if (Number.isFinite(maxEditar)) {
          inputRef.dataset.maxEdit = String(maxEditar);
        } else {
          inputRef.dataset.maxEdit = '';
        }
      }

      maxFromEdit = parseNum(inputRef.dataset.maxEdit);
    }
  } else {
    //console.log('Modo detectado: AGREGAR');
  }
} catch (e) {
  //console.warn('Error detectando modal de edición o capturando maxFromEdit:', e);
}

// Normalizar restante
if (!Number.isFinite(restante) || restante < 0) {
  restante = 0;
}

// ---------------- Calcular el máximo permitido ----------------
let max;
if (isEdit) {
  if (Number.isFinite(maxFromEdit)) {
    max = maxFromEdit;
  } else if (Number.isFinite(maxEditar)) {
    max = maxEditar;
  } else {
    max = restante;
  }
} else {
  max = restante;
}

// Si el valor no es numérico, devolvemos lo que haya sin validar
if (!Number.isFinite(val)) {
  return this.frm_coaseguro_participacion ?? null;
}

const fmtNum = (n) => String(n).replace('.', ',');

let invalid = false;
let msg = '';

// ---------------- Lógica de validación ----------------
if (!isEdit && max === 0) {
  invalid = true;
  msg = 'No se pueden registrar más coaseguros porque la participación total ya alcanza el 100%.';
} else if (val < 0 || val > max) {
  invalid = true;
  msg = `La participación ingresada debe estar entre 0 y ${fmtNum(max)}.`;
}

// ------- Helper para obtener el modal ACTIVO (ADD o EDIT) -------
const getVisibleModalRoot = () => {
  const containers = document.querySelectorAll('[data-cy="modal-add"], [data-cy="modal-edit"]');

  for (const container of containers) {
    if (isContainerVisible(container)) {
      return container;
    }
  }

  // Fallback: cualquier modal con display:block
  const anyDialog = document.querySelector(
    'div[role="dialog"].modal.fade.show[style*="display: block"]'
  );
  return anyDialog ? anyDialog.closest('.modal') || anyDialog : document;
};

// ---------------- Pintar el error en el modal ACTIVO ----------------
setTimeout(() => {
  const root = getVisibleModalRoot();

  const input = root.querySelector('input[name="frm_coaseguro_participacion"]');
  const group = input?.closest('.form-group');

  if (!input || !group) {
    //console.warn('No se encontró input o form-group para pintar el error.');
    return;
  }

  let feedback = group.querySelector('.invalid-feedback');
  if (!feedback) {
    feedback = document.createElement('div');
    feedback.className = 'invalid-feedback';
    group.appendChild(feedback);
  }

  input.classList.remove('is-invalid');

  if (invalid) {
    if (!input.classList.contains('is-invalid')) {
      input.classList.add('is-invalid');
    }
    feedback.innerHTML = msg;
  }
}, 200);

// ---------------- Control del valor devuelto ----------------
if (invalid) {
  //console.log('invalid = true, se retorna null para bloquear el guardado.');
  return null;
}

// Si es válido, devolvemos el número
return val;

setTimeout(() => {
  try {
    // Helper: ver si un contenedor [data-cy="modal-xxx"] está visible
    const isContainerVisible = (container) => {
      if (!container) return false;
      const dialog = container.querySelector('div[role="dialog"]');
      if (!dialog) return false;

      const inlineDisplay = dialog.style && dialog.style.display;
      const display =
        inlineDisplay && inlineDisplay.trim() !== ''
          ? inlineDisplay
          : window.getComputedStyle(dialog).display;

      return display !== 'none';
    };

    // 1) Buscar los contenedores de ADD y EDIT
    const containers = document.querySelectorAll(
      '[data-cy="modal-add"], [data-cy="modal-edit"]'
    );

    let activeContainer = null;
    for (const c of containers) {
      if (isContainerVisible(c)) {
        activeContainer = c;
        break;
      }
    }

    // Si no encontramos una modal visible, no hacemos nada
    if (!activeContainer) return;

    // 2) Desde el contenedor activo, buscamos el .modal-dialog
    const modalDialog = activeContainer.querySelector('.modal-dialog');
    if (!modalDialog) return;

    const footer = modalDialog.querySelector('.modal-footer');
    if (!footer) return;

    const aceptarBtn = footer.querySelector('button.btn.btn-primary');
    if (!aceptarBtn) return;

    console.log('🟦 Botón Aceptar detectado en modal activa:', aceptarBtn);

    // Función helper para saber si hay algún error visible en ESTA modal
    const tieneErroresVisibles = () => {
      const invalids = Array.from(
        modalDialog.querySelectorAll('.invalid-feedback')
      );

      return invalids.some((div) => {
        const style = window.getComputedStyle(div);
        const visible =
          style.display !== 'none' &&
          style.visibility !== 'hidden' &&
          style.opacity !== '0';

        const msgRaw = (div.textContent || '').trim();

        return visible && msgRaw; // cualquier mensaje visible con texto
      });
    };

    const hayErrorVisible = tieneErroresVisibles();

    // 🔐 Estado visual del botón
    aceptarBtn.disabled = hayErrorVisible;
    aceptarBtn.classList.toggle('disabled', hayErrorVisible);

    // Parche extra: interceptar el click y bloquearlo si hay errores
    if (!aceptarBtn._coaseguroGuard) {
      aceptarBtn._coaseguroGuard = true;

      aceptarBtn.addEventListener(
        'click',
        (e) => {
          const bloqueaAhora = tieneErroresVisibles();

          if (bloqueaAhora) {
            e.stopImmediatePropagation?.();
            e.stopPropagation();
            e.preventDefault();
            return false;
          }
        },
        true // captura, para adelantarnos al handler de Vue
      );
    }
  } catch (err) {
    //console.error('Error en controlBotonAceptarCoaseguro:', err);
  }
}, 0);

return '';

const raw = this.frm_coaseguro_participacion;
  if (raw == null || raw === "") return "";

  let s = String(raw).trim().replace(/\s/g, "").replace(/%/g, "");

  s = s.replace(",", ".");

  s = s.replace(/[^0-9.-]/g, "");

  const n = Number(s);
  if (!Number.isFinite(n)) return "";

  return `${n}%`;

const rows = this.frm_lista_coaseguro || [];
if (!Array.isArray(rows)) return "";

const counts = new Map();

for (const r of rows) {
  const compania_nombre = (r.frm_coaseguro_compania_coaseguradora_nombre || "")
    .trim()
    .toLowerCase();

  if (!compania_nombre) continue;

  counts.set(compania_nombre, (counts.get(compania_nombre) || 0) + 1);
}

const duplicates = [];
for (const [compania_nombre, n] of counts.entries()) {
  if (n > 1) duplicates.push(compania_nombre);
}

return duplicates.join(", "); // ejemplo: "a@x.com, b@y.com"

const rows = this.frm_lista_coaseguro || [];

if (!Array.isArray(rows)) return "false";

const seen = new Set();

for (const r of rows) {
  const compania_nombre = (r.frm_coaseguro_compania_coaseguradora_nombre || "")
    .trim();

  if (!compania_nombre) continue; // ignora vacíos o null

  if (seen.has(compania_nombre)) return "true"; // duplicado encontrado
  seen.add(compania_nombre);
}

return "false";

