/* Variante para mostrarlo hacia arriba cuando no hay espacio abajo */
[selector="list-record-4"] td[aria-colindex="3"] .actions .popover-content.popover--top{
  top: auto;
  bottom: calc(100% + 8px);
}
[selector="list-record-4"] td[aria-colindex="3"] .actions .popover-content.popover--top::before{
  top: auto;
  bottom: -6px;
  border-color: #fff transparent transparent transparent;
  filter: drop-shadow(0 1px 0 #e5e7eb);
}


/* Limitar el alcance a tu tabla */
[selector="list-record-4"] .actions .popover-content p,
[selector="list-record-4"] .actions .popover-content .btn {
  position: relative;
