  font-size: 0 !important;
}

/* Texto del mensaje */
[selector="list-record-4"] .actions .popover-content p::after {
  content: "¿Confirmas que deseas eliminar este registro?";
  font-size: 0.95rem;
  color: #111827;
  line-height: 1.35;
  display: block;
}

/* Botón CANCEL → Cancelar */
[selector="list-record-4"] .actions .popover-content .btn.btn-light::after {
  content: "Cancelar";
  font-size: 0.875rem;
  color: #374151;
}

/* Botón DELETE → Eliminar */
[selector="list-record-4"] .actions .popover-content .btn.btn-danger::after {
  content: "Eliminar";
  font-size: 0.875rem;
  color: #fff;
}

/* Mantener clics y foco normal (el pseudo no captura eventos) */
[selector="list-record-4"] .actions .popover-content p::after,
[selector="list-record-4"] .actions .popover-content .btn::after {
  pointer-events: none;
}

[selector="list-record-4"] .data-table.max-rows [data-cy="add-row"].btn {
  display: none !important;
}

/* Ocultar botón "Eliminar" solo en la primera fila */
[selector="list-record-4"]
table.record-list-table-secondary tbody tr:first-child
td[aria-colindex="3"] .actions [title="Eliminar"] {
  display: none !important;
}

