[selector="list-record-reaseguro"] td[aria-colindex="3"] .actions [title="Editar"] img{
  transition: filter .15s ease, transform .12s ease;
  filter: invert(17%) sepia(22%) saturate(2557%) hue-rotate(171deg) brightness(92%) contrast(92%);
