  display: block;
}

/* Botón CANCEL → Cancelar */
[selector="list-record-reaseguro"] .actions .popover-content .btn.btn-light::after {
  content: "Cancelar";
  font-size: 0.875rem;
  color: #374151;
}

/* Botón DELETE → Eliminar */
[selector="list-record-reaseguro"] .actions .popover-content .btn.btn-danger::after {
  content: "Eliminar";
  font-size: 0.875rem;
  color: #fff;
}

/* Mantener clics y foco normal (el pseudo no captura eventos) */
[selector="list-record-reaseguro"] .actions .popover-content p::after,
[selector="list-record-reaseguro"] .actions .popover-content .btn::after {
  pointer-events: none;
}

[selector="list-record-reaseguro"] .data-table.max-rows [data-cy="add-row"].btn {
  display: none !important;
}

/* Ocultar botón "Eliminar" solo en la primera fila */
[selector="list-record-reaseguro"]
table.record-list-table-secondary tbody tr:first-child
td[aria-colindex="3"] .actions [title="Eliminar"] {
  display: none !important;
}

scripts.code:
try {

function formatoCOP(valor) {
  if (valor === null || valor === undefined || valor === "") return "";
  const numero = Number(valor);
  if (isNaN(numero)) return "";

  return new Intl.NumberFormat("es-CO", {
    minimumFractionDigits: 0,
    maximumFractionDigits: 0
  }).format(numero);
}



  function parseISODate(s) {
    const m = /^(\d{4})-(\d{2})-(\d{2})$/.exec((s ?? "").toString().trim());
    if (!m) return null;
    const y = +m[1], mo = +m[2], d = +m[3];
    if (mo < 1 || mo > 12) return null;
    if (d < 1 || d > 31) return null;
    return { y, m: mo, d };
  }

  function makeLocalDate(parsed) {
    return new Date(parsed.y, parsed.m - 1, parsed.d);
  }

  const DIAS  = ['domingo','lunes','martes','miércoles','jueves','viernes','sábado'];
  const MESES = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];

  // "Desde el martes 9 de julio del 2024 a las 00:00 Horas"
  function formateaLinea(prefix, dt, horaTexto) {
    const diaSemana = DIAS[dt.getDay()];
    const dia = dt.getDate();
    const mes = MESES[dt.getMonth()];
    const anio = dt.getFullYear();
    return `${prefix} ${diaSemana} ${dia} de ${mes} del ${anio} a las ${horaTexto} Horas`;
  }

  // "2025-09-09, martes, 9 de septiembre de 2025"
  function formateaFechaEtiqueta(fechaStr) {
    const parsed = parseISODate(fechaStr);
    if (!parsed) return null;
    const dt = makeLocalDate(parsed);
    let diaSemana = DIAS[dt.getDay()];
    diaSemana = diaSemana.charAt(0).toUpperCase() + diaSemana.slice(1);
    const dia = dt.getDate();
    const mes = MESES[dt.getMonth()];
    const anio = dt.getFullYear();
    return `${diaSemana}, ${dia} de ${mes} de ${anio}`;
  }


  // Entradas

  const pais = (data.frm_gen_pais ?? "").toString().trim().toUpperCase();
  const ini  = parseISODate(data.frm_cot_fecha_inicio_vigencia);
  const fin  = parseISODate(data.frm_cot_fecha_fin_vigencia);
  const fechaCotStr = (data.frm_gen_fecha_cotizacion ?? "").toString().trim();


  // Catálogos

  const MONEDAS = {
    CO: "Pesos Colombianos (COP)",
    CL: "Unidad de Fomento (UF - CLF)",
    MX: "Pesos Mexicanos (MXN)"
  };
  const AMBITO = {
    CO: "Territorio colombiano",
    CL: "Territorio chileno",
    MX: "Territorio mexicano"
  };


  // Cálculos

  const frm_moneda =
    pais ? (MONEDAS[pais] ?? "Moneda no definida") : (data.frm_moneda ?? null);

  const frm_ambito_territorial =
    pais ? (AMBITO[pais] ?? "Territorio no definido") : (data.frm_ambito_territorial ?? null);

  const frm_inicio_vigencia_formateado =
    ini ? formateaLinea("Desde el", makeLocalDate(ini), "00:00") : (data.frm_inicio_vigencia_formateado ?? null);

  // Nota: "24:00" solo como texto (JS no acepta 24:00 como hora).
  const frm_fin_vigencia_formateado =
    fin ? formateaLinea("Hasta el", makeLocalDate(fin), "24:00") : (data.frm_fin_vigencia_formateado ?? null);

  const frm_fecha_cotizacion_formateado =
    fechaCotStr ? (formateaFechaEtiqueta(fechaCotStr) ?? (data.frm_fecha_cotizacion_formateado ?? null))
                : (data.frm_fecha_cotizacion_formateado ?? null);

 // --- lógica de cocorretaje ---
  const frm_gen_incluye_cocorretaje_flag = (data.frm_gen_incluye_cocorretaje_flag ?? "").toString().trim().toUpperCase();

  // valor base (lo que venga del formulario, por si luego lo usas para otra cosa)
  let frm_gen_intermediario_principal_pct =
    data.frm_gen_intermediario_principal_pct ?? null;

  // si NO incluye cocorretaje => 100%
  if (frm_gen_incluye_cocorretaje_flag === "NO") {
    frm_gen_intermediario_principal_pct = 100;
  }

  // --- Formateo de valores monetarios (COP) ---

const frm_valor_asegurado_opcion_1_formateado = formatoCOP(data.frm_valor_asegurado_opcion_1);
const frm_valor_asegurado_opcion_2_formateado = formatoCOP(data.frm_valor_asegurado_opcion_2);
const frm_valor_asegurado_opcion_3_formateado = formatoCOP(data.frm_valor_asegurado_opcion_3);

const grd_cot_primaAntesIva_Opc1_formateado = formatoCOP(data.grd_cot_primaAntesIva_Opc1);
const grd_cot_primaAntesIva_Opc2_formateado = formatoCOP(data.grd_cot_primaAntesIva_Opc2);
const grd_cot_primaAntesIva_Opc3_formateado = formatoCOP(data.grd_cot_primaAntesIva_Opc3);


  // Salida (merge en pantalla)

  return {
    frm_moneda,
    frm_ambito_territorial,
    frm_inicio_vigencia_formateado,
    frm_fin_vigencia_formateado,
    frm_fecha_cotizacion_formateado,
    frm_gen_intermediario_principal_pct,

    frm_valor_asegurado_opcion_1_formateado,
    frm_valor_asegurado_opcion_2_formateado,
    frm_valor_asegurado_opcion_3_formateado,
    grd_cot_primaAntesIva_Opc1_formateado,
    grd_cot_primaAntesIva_Opc2_formateado,
    grd_cot_primaAntesIva_Opc3_formateado   
  };

} catch (e) {
  // Fallback: conserva valores actuales si existen
  return {
    frm_moneda: this.frm_moneda ?? null,
    frm_ambito_territorial: this.frm_ambito_territorial ?? null,
    frm_inicio_vigencia_formateado: this.frm_inicio_vigencia_formateado ?? null,
    frm_fin_vigencia_formateado: this.frm_fin_vigencia_formateado ?? null,
    frm_fecha_cotizacion_formateado: this.frm_fecha_cotizacion_formateado ?? null,
    frm_gen_intermediario_principal_pct: this.frm_gen_intermediario_principal_pct ?? null,

    frm_valor_asegurado_opcion_1_formateado: this.frm_valor_asegurado_opcion_1_formateado ?? null,
    frm_valor_asegurado_opcion_2_formateado: this.frm_valor_asegurado_opcion_2_formateado ?? null,
    frm_valor_asegurado_opcion_3_formateado: this.frm_valor_asegurado_opcion_3_formateado ?? null,
    grd_cot_primaAntesIva_Opc1_formateado: this.grd_cot_primaAntesIva_Opc1_formateado ?? null,
    grd_cot_primaAntesIva_Opc2_formateado: this.grd_cot_primaAntesIva_Opc2_formateado ?? null,
    grd_cot_primaAntesIva_Opc3_formateado: this.grd_cot_primaAntesIva_Opc3_formateado ?? null
  };
}
